import {
  AfterViewInit,
  Component,
  DestroyRef,
  ElementRef,
  HostListener,
  OnDestroy,
  OnInit,
  Renderer2,
  effect,
  inject,
  input,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { BreakpointObserver, Breakpoints } from '@angular/cdk/layout';
import { Subject, debounceTime, takeUntil } from 'rxjs';

import { SplitterModule } from 'primeng/splitter';
import { ButtonModule } from 'primeng/button';

import {
  LayoutMode,
  LayoutState,
  PanelConfig,
  PanelState,
} from '../../../models/layout.model';
import { LocalStorageService } from '../../../services/local-storage.service';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  hasProperty,
  isArray,
  isDefined,
  isEmpty,
  isNullOrUndefined,
  isNumber,
  isObject,
  isString,
} from '../../../utils';

@Component({
  selector: 'app-adaptive-layout',
  imports: [CommonModule, SplitterModule, ButtonModule],
  templateUrl: './adaptive-layout.component.html',
  styleUrl: './adaptive-layout.component.scss',
})
export class AdaptiveLayoutComponent
  implements OnInit, OnDestroy, AfterViewInit
{
  readonly panels = input<PanelConfig[]>([]);
  readonly height = input<string>('100%');
  readonly stateKey = input<string>('splitter-state');
  readonly defaultSizes = input<number[]>([]);
  readonly minSizes = input<number[]>([]);
  readonly defaultLayout = input<LayoutMode>('horizontal');
  readonly responsive = input<boolean>(true);

  private readonly destroy$ = new Subject<void>();
  private readonly resizeSubject = new Subject<void>();
  private static readonly DEFAULT_MIN_SIZE = 0;
  private static readonly DEFAULT_MAX_SIZE = 100;
  private static readonly COLLAPSED_PANEL_SIZE = 40;

  readonly panelSizes = input<number[]>([25, 75]);
  panelStates: PanelState[] = [];
  stateStorage = 'session';
  currentLayout: LayoutMode = 'horizontal';
  currentHeight = '100%';
  containerClass = '';
  touchStartX = 0;
  private readonly destroyRef = inject(DestroyRef);
  private readonly breakpointObserver = inject(BreakpointObserver);
  private readonly elementRef = inject(ElementRef);
  private readonly renderer = inject(Renderer2);

  constructor(private readonly localStorage: LocalStorageService) {
    this.setupResizeListener();
    effect(() => {
      // Read the panelSizes input to track it
      const sizes = this.panelSizes();

      // Skip immediate execution during initialization
      if (isNullOrUndefined(this.elementRef?.nativeElement)) return;

      // Apply hidden panel styles with a small delay to ensure DOM is ready
      setTimeout(() => this.applyHiddenPanelStyles(sizes), 0);
    });
  }

  ngOnInit() {
    this.initializePanelStates();
    this.loadSavedState();
    this.currentHeight = this.height();
    this.breakpointObserver
      .observe([Breakpoints.Handset, Breakpoints.Tablet])
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((result) => {
        this.currentLayout = result.matches ? 'vertical' : 'horizontal';
      });
  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
    this.resizeSubject.complete();
  }

  ngAfterViewInit() {
    // Apply styling after view initialization
    this.applyHiddenPanelStyles(this.panelSizes());
  }

  /**
   * Apply special styles to panels that should be hidden
   * @param panelSizes The current panel sizes to evaluate
   */
  private applyHiddenPanelStyles(panelSizes: number[]) {
    if (isNullOrUndefined(this.elementRef?.nativeElement)) return;

    if (isEmpty(panelSizes)) return;

    const hasHiddenPanel = panelSizes.some((size) => size === 0);

    if (hasHiddenPanel) {
      this.renderer.addClass(this.elementRef.nativeElement, 'has-hidden-panel');
    } else {
      this.renderer.removeClass(
        this.elementRef.nativeElement,
        'has-hidden-panel',
      );
    }

    // Apply individual panel classes
    const panelElements =
      this.elementRef.nativeElement.querySelectorAll('.p-splitter-panel');

    if (!isEmpty(panelElements)) {
      panelSizes.forEach((size, index) => {
        if (index < panelElements.length) {
          const panel = panelElements[index];
          if (size === 0) {
            this.renderer.addClass(panel, 'zero-width-panel');
            // Also hide the splitter gutter if this panel is zero-width
            const gutter = this.elementRef.nativeElement.querySelector(
              `.p-splitter-gutter:nth-of-type(${index * 2 + 1})`,
            );
            if (isDefined(gutter)) {
              this.renderer.setStyle(gutter, 'display', 'none');
            }
          } else {
            this.renderer.removeClass(panel, 'zero-width-panel');
            // Make gutter visible again
            const gutter = this.elementRef.nativeElement.querySelector(
              `.p-splitter-gutter:nth-of-type(${index * 2 + 1})`,
            );
            if (isDefined(gutter)) {
              this.renderer.removeStyle(gutter, 'display');
            }
          }
        }
      });
    }
  }

  private setupResizeListener() {
    this.resizeSubject
      .pipe(debounceTime(250), takeUntil(this.destroy$))
      .subscribe({ error: (error) => console.error('Resize error:', error) });
  }

  @HostListener('window:resize')
  onResize() {
    if (this.responsive()) {
      this.resizeSubject.next();
    }
  }

  private initializePanelStates() {
    if (!isArray(this.panels())) {
      console.warn('No panels provided for initialization');
      return;
    }

    this.panelStates = this.panels().map((panel, _index) => {
      const defaultSize = 100 / this.panels().length;

      return {
        size: isNumber(defaultSize) ? defaultSize : 0,
        collapsed: false,
        minSize:
          isDefined(panel) && isNumber(panel.minSize)
            ? panel.minSize
            : AdaptiveLayoutComponent.DEFAULT_MIN_SIZE,
        maxSize:
          isDefined(panel) && isNumber(panel.maxSize)
            ? panel.maxSize
            : AdaptiveLayoutComponent.DEFAULT_MAX_SIZE,
        hidden: false,
      };
    });
  }

  private loadSavedState() {
    try {
      const savedState: LayoutState | null =
        this.localStorage.getItem<LayoutState>(this.stateKey());
      if (!savedState) {
        this.currentLayout = this.defaultLayout();
        return;
      }

      const state: LayoutState = savedState;
      if (!this.isValidState(state)) {
        return;
      }

      this.panelStates = state.panelStates;
      this.currentLayout = state.layoutMode;
    } catch (e) {
      console.error('Error loading saved state:', e);
    }
  }

  private isValidState(state: unknown): state is LayoutState {
    return (
      isObject(state) &&
      hasProperty(state, 'panelStates') &&
      hasProperty(state, 'panelSizes') &&
      hasProperty(state, 'layoutMode') &&
      Array.isArray(state['panelStates']) &&
      Array.isArray(state['panelSizes']) &&
      isString(state['layoutMode'])
    );
  }

  // Touch support handlers
  private calculatePercentageMoved(diff: number): number {
    return (diff / window.innerWidth) * 100;
  }

  private updatePanelSize(panelIndex: number, percentageMoved: number): void {
    if (!isNumber(panelIndex) || !isNumber(percentageMoved)) {
      console.warn('Invalid parameters for panel size update');
      return;
    }

    const currentPanel = this.panelStates[panelIndex];
    if (!isDefined(currentPanel)) {
      console.warn('Panel not found at index:', panelIndex);
      return;
    }

    const minSize = isNumber(currentPanel.minSize) ? currentPanel.minSize : 10;
    const maxSize = isNumber(currentPanel.maxSize) ? currentPanel.maxSize : 90;
    const currentSize = this.panelSizes()[panelIndex];

    if (!isNumber(currentSize)) {
      console.warn('Invalid current panel size');
      return;
    }

    const newSize = Math.max(
      minSize,
      Math.min(maxSize, currentSize + percentageMoved),
    );

    if (newSize !== currentSize) {
      this.panelSizes()[panelIndex] = newSize;
    }
  }

  private getPanelIndex(touchX: number): number {
    let cumulativeWidth = 0;
    for (let i = 0; i < this.panelSizes.length; i++) {
      cumulativeWidth += (this.panelSizes()[i] / 100) * window.innerWidth;
      if (touchX < cumulativeWidth) {
        return i;
      }
    }
    return this.panelSizes.length - 1; // Default to the last panel if not found
  }

  handleTouchStart(event: TouchEvent) {
    this.touchStartX = event.touches[0].clientX;
  }

  handleTouchMove(event: TouchEvent) {
    const touchX = event.touches[0].clientX;
    const diff = touchX - this.touchStartX;

    if (Math.abs(diff) > 10) {
      event.preventDefault();
      const percentageMoved = this.calculatePercentageMoved(diff);
      const panelIndex = this.getPanelIndex(touchX);
      this.updatePanelSize(panelIndex, percentageMoved);
    }
  }

  handleTouchEnd(_event: TouchEvent) {
    this.touchStartX = 0;
  }
}
